from typing import List


class Solution:
    def minimumLatency(self, nums: List[int], k: int) -> int:
        def can(limit: int) -> bool:
            cnt = 1
            s = 0
            for x in nums:
                # 当前段再加 x 会超限，则开启新通道
                if s + x > limit:
                    cnt += 1
                    s = 0
                s += x
            # 所需段数不超过 k 则 limit 可行
            return cnt <= k

        lo, hi = max(nums), sum(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if can(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo
```

```java
public class Solution {
    public int minimumLatency(int[] nums, int k) {
        int lo = 0, hi = 0;
        for (int x : nums) {
            lo = Math.max(lo, x);
            hi += x;
        }

        while (lo < hi) {
            int mid = lo + (hi - lo) / 2;
            if (canSplit(nums, k, mid))
                hi = mid;
            else
                lo = mid + 1;
        }
        return lo;
    }

    private boolean canSplit(int[] nums, int k, int limit) {
        int cnt = 1;
        long s = 0;
        for (int x : nums) {
            if (s + x > limit) {
                cnt++;
                s = 0;
            }
            s += x;
        }
        // 贪心段数不超过 k 即可通过二分
        return cnt <= k;
    }
}
