var minimumLatency = function(nums, k) {
    // 贪心检验：limit下所需最少段数是否不超过k
    function canSplit(limit) {
        var cnt = 1, s = 0;
        for (var i = 0; i < nums.length; i++) {
            if (s + nums[i] > limit) {
                cnt++;
                s = 0;
            }
            s += nums[i];
        }
        return cnt <= k;
    }

    var lo = Math.max.apply(null, nums), hi = 0;
    for (var i = 0; i < nums.length; i++) hi += nums[i];

    // 二分查找最小的可行limit
    while (lo < hi) {
        var mid = Math.floor((lo + hi) / 2);
        if (canSplit(mid)) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
