#include <stdlib.h>

// 贪心检验：limit下所需最少段数是否不超过k
static int canSplit(int* nums, int n, int k, long long limit) {
    int cnt = 1;
    long long s = 0;
    for (int i = 0; i < n; i++) {
        if (s + nums[i] > limit) {
            cnt++;
            s = 0;
        }
        s += nums[i];
    }
    return cnt <= k;
}

int minimumLatency(int* nums, int numsSize, int k) {
    long long lo = 0, hi = 0;
    for (int i = 0; i < numsSize; i++) {
        if (nums[i] > lo) lo = nums[i];
        hi += nums[i];
    }

    // 二分查找最小的可行limit
    while (lo < hi) {
        long long mid = (lo + hi) / 2;
        if (canSplit(nums, numsSize, k, mid))
            hi = mid;
        else
            lo = mid + 1;
    }
    return (int)lo;
}
